SELECT SUM(views) AS total_views
FROM asset_engagement
WHERE asset_id = 0;

SELECT COUNT(*) AS report_count
FROM asset_reports
WHERE generated_by = 1;

SELECT COUNT(update_id) AS update_count
FROM asset_updates
WHERE asset_id = 1;

SELECT COUNT(asset_id) AS event_asset_count
FROM asset_labels
WHERE label_name = 'event';

SELECT COUNT(comment_id) AS total_comments
FROM asset_comments
WHERE asset_id = 1;

SELECT COUNT(*) AS permission_count
FROM asset_permissions
WHERE granted_by = 0;
